var e=JSON.parse(`[{"id":"L3_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"……하.","JPN":"……は。","ENG":"*...Sigh*","TWN":"……哈。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L4_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"이건 예상에 없어서 더 당황스럽네. 그동안 내 뒤꽁무니를 쫓는 것만으로는 부족했어?","JPN":"予想外のことすぎて対応に困るわね。私の後をつけるだけじゃ足りなかったの？","ENG":"Didn't see this one coming. Was tailing me around not enough for you?","TWN":"這真是出乎意料，讓我更加慌亂。難道之前只是跟在我後面還不夠嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L5_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"몇 번이나 만나러 갔는데 만남을 거부한 건 경이 아니십니까.","JPN":"何度も会いに行ったのに拒んだのはあなたではありませんか。","ENG":"I tried to meet you several times. You're the one who refused every time, weren't you?","TWN":"我去見了好幾次，但拒絕見面的不是你嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L8_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"가문의 기사들에게 들었어. 버고 소드를 놔두고 돌연 자취를 감췄다면서?","JPN":"家の騎士たちから聞いたわ。ヴァルゴソードを置いて突然姿を消したんだって？","ENG":"I heard from your knights. You left the Virgo Sword behind and just disappeared?","TWN":"我聽家族的騎士們說了。你突然消失了，留下布林加夫之劍不管不顧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"우리 아가씨에게 무슨 바람이 분 걸까? 오빠 흉내를 내니 그런 것까지 따라하고 싶었어?","JPN":"どういう風の吹き回しかしら？　そんなところまでお兄さんの真似がしたかった？","ENG":"What's gotten into our little lady? Playing copycat with your brother now, too?","TWN":"你是受了什麼風的影響嗎？模仿哥哥連這種事情都想學嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"아니면, 가출이라도 하니 집이 그리워졌어? 내 지지를 얻어 단장 자리라도 되찾으려고?","JPN":"それとも、家出したら家が恋しくなった？　私の支持を得て、団長の座を取り戻すつもり？","ENG":"Or what, ran away from home and now you're homesick? Hoping to win my favor and reclaim your title?","TWN":"還是說，你離家出走了，現在想家了？想要得到我的支持，重新奪回團長的位置嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"메데이아 경이 그러더군요. 전임 기사단장은 책임을 저버릴 사람이 아니라고.","JPN":"メデイア卿から聞きました。前騎士団長は責任を放棄するような人間ではないと。","ENG":"Dame Medea told me... the former captain was not the kind of man to abandon his duty.","TWN":"美狄亞這麼說過。前任騎士團團長不是一個會逃避責任的人。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"저는 진실을 알기 위해 찾아왔습니다, 레온하르트 경.","JPN":"私は真実を知るために来たんです、レオンハルト卿。","ENG":"I came to find the truth, Dame Leonhardt.","TWN":"我來是為了尋找真相，里恩哈特。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L15_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"오빠가 버고 소드를 내려놓고… 레드시프트의 행방을 찾아 떠난 그 날의 진실을요.","JPN":"兄がヴァルゴソードを手放し……レッドシフトの行方を探しに出たあの日の真実を。","ENG":"The truth behind the day my brother gave up the Virgo Sword... and left to find Red Shift.","TWN":"哥哥放下了布林加夫之劍……去尋找紅移下落的那天的真相。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L16_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…그 망할 계집. 쓸데없는 소리 떠벌리고 다니긴.","JPN":"……あの女。余計なこと言いやがって。","ENG":"...That damn girl. Running her mouth again where she shouldn't.","TWN":"……那個該死的。到處說些廢話。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L18_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"좋아. 네 오빠에 대해 궁금하다면 알려주지, 뭐.","JPN":"そう。あなたのお兄さんについてそんなに知りたいなら、教えてあげてもいいわよ。","ENG":"Fine. If you're so curious about your brother, I'll tell you.","TWN":"好吧。如果你對你哥哥感興趣，我可以告訴你一些事情。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"그게 정말이십니까?","JPN":"本当ですか？","ENG":"You really mean it?","TWN":"你說的是真的嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그래~. 네 오빠는 말이지~.","JPN":"ええ～。あなたのお兄さんはね～","ENG":"Sure. Your brother, well...","TWN":"是啊～你哥哥就是這樣～"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L25_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"단장의 책임을 등한시하다 버고 소드에게 버림받은 걸 인정하지 못하고 도망쳤어.","JPN":"団長の責任を疎かにしてヴァルゴソードに捨てられたことが受け入れられず、逃げたの。","ENG":"He ran away because he couldn't accept that the Virgo Sword had abandoned him for failing his duties.","TWN":"因為忽視團長的責任，被布林加夫之劍拋棄，卻無法承認這一點而逃跑了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"레드시프트를 찾아 떠났다는 건 형편 좋은 변명이지.","JPN":"レッドシフトを探すなんて、都合のいい口実だったわ。","ENG":"That story about searching for Red Shift? Just a pretty excuse.","TWN":"說是去尋找紅移，不過是個不錯的藉口罷了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L30_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"표정이 왜 그래? 혹시 네 오빠가 세상을 구하다 죽은 영웅이라도 되는 줄 아니?","JPN":"何その顔？　もしかして、お兄さんは世界を救おうとして死んだ英雄だとでも思ってた？","ENG":"Why the face? Did you think he was some fallen hero who died saving the world?","TWN":"表情怎麼這樣？難道你以為你哥哥是拯救世界而犧牲的英雄嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_SURPRISE"}}}},{"id":"L31_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"정신 차려, 아가씨. 기사단이 말하는 <color=#ffd34c>정의</color>는 전부 허상이야.","JPN":"目を覚ましなさい、お嬢さん。騎士団の言う<color=#ffd34c>正義</color>は全部虚像よ。","ENG":"Wake up, girl. That <color=#ffd34c>justice</color> the knights go on about? It's all just a fantasy.","TWN":"清醒點，小姐。騎士團所說的<color=#ffd34c>正義</color>全都是虛幻的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L32_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"혹시 정의로움이 세상을 바꿀 수 있다고 믿는 정신병자들이 있다면…….","JPN":"正義で世界を変えられるなんてほざく狂人がいるなら……","ENG":"If there really are lunatics who think justice can save the world...","TWN":"如果說有些精神病患者能用正義改變世界的話……"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"그런 놈들. 엿이나 먹으라지. 꽃밭인 머리로 눈 가리고 아웅하는 것도 지겨우니까.","JPN":"くそくらえだ。脳みそお花畑で、現実から目を逸らすのもいい加減にしなさいっての。","ENG":"They can go choke on it. I'm sick of all that starry-eyed, make-believe crap.","TWN":"那些傢伙。讓他們去死吧。整天腦子裡裝這些荒唐的想法都夠煩了。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"C":null,"R":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_HATE"}}}},{"id":"L35_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"왜… 그런 소리를 하는 거죠?","JPN":"なぜ……そんなことを言うのですか？","ENG":"Why... would you say something like that?","TWN":"為什麼……要說那種話呢？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"적어도 당신만큼은 그런 소리를 하면 안 되는 게 아닙니까?","JPN":"少なくともあなただけは、そう言ってはいけないのではありませんか？","ENG":"You, of all people shouldn't be the one saying it.","TWN":"至少你不應該說這種話吧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"ESTAROSSA_NPC_NULL_NULL","text":{"KOREA":"당신은, 전임 기사단장 시절……!","JPN":"あなたは、前騎士団長の頃……！","ENG":"You were captain once...!","TWN":"你是，前任騎士團長時期……！"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"ESTAROSSA_NPC_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"옛날 일로 질척거리지 마. 지금 블루시프트의 부단장은 피오네잖니?","JPN":"昔のことで付きまとわないで。今ブルーシフトの副団長はフィオネよ？","ENG":"Spare me the nostalgia. The deputy of Blue Shift now is Fione, isn't it?","TWN":"別糾結於過去的事情了。現在藍移的副團長是菲奧尼吧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"네가 없다고 아등바등하는 모양인데… 안 되지. 피오네는 재능이 없거든.","JPN":"あなたの不在で苦労してるみたいだけど……ダメね。フィオネには才能がないもの。","ENG":"Seems like she's struggling now that you're gone... Poor thing. Not much talent, that one.","TWN":"看來你不在的時候他們都手忙腳亂的……不行啊。因為菲奧尼沒有天賦。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"GOLD_CHARADE_NULL_NULL","text":{"KOREA":"당장 건틀렛에서 카운터도 아닌 애 상대로 애먹는 걸 보면 그동안 어지간히 놀았나 봐?","JPN":"ガントレットでカウンターでもない子相手に手こずってるわけだし、今まで遊んでばかりいたようね？","ENG":"Struggling in the Gauntlet against someone who's not even a Counter? Looks like she's been slacking off.","TWN":"看你在聖鎧中對付一個非制裁者都這麼吃力，看來你之前真是玩得太過了吧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"GOLD_CHARADE_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};